class Solution:
    def climbStairs(self, n):
        from functools import lru_cache
        @lru_cache(None)
        def f(k):
            if k <= 1:
                return 1
            return f(k - 1) + f(k - 2)
        return f(n)

solutions.python:
class Solution:
    def climbStairs(self, n):
        a, b = 1, 1
        for _ in range(n):
            a, b = b, a + b
        return a

